const now = new Date().toISOString();
console.log('🧪 BASELINE TEST START — Paid Models (GPT 5.2 Neuro/Polza)');
console.log('📅 Timestamp: ' + now);
return [{ json: { test_id: 'baseline-paid-001', test_date: now, test_name: 'Baseline — Paid Models', model: 'GPT 5.2 Neuro → Polza (fallback Claude 4.5)', start_time: Date.now() } }];

const testStart = $('Log: Baseline Start').first().json;
const dbResult = $('INSERT Test Data in DB').first().json;
const translateResult = $input.first().json;

const endTime = Date.now();
const totalDuration = endTime - testStart.start_time;

const report = `
═══════════════════════════════════════
🧪 BASELINE TEST — PAID MODELS REPORT
═══════════════════════════════════════
📋 Test ID: ${testStart.test_id}
📅 Date: ${testStart.test_date}
🤖 Models: GPT 5.2 Neuro → GPT 5.2 Polza → Claude 4.5 (fallback)
📄 File: Тест2.docx
📥 Input chunk_id: ${dbResult.id_chunk}
⏱️  Total Duration: ${totalDuration} ms (${(totalDuration/1000).toFixed(1)} sec)

📊 RESULT:
${JSON.stringify(translateResult, null, 2)}
═══════════════════════════════════════
`.trim();

console.log(report);

return [{
  json: {
    test_id: testStart.test_id,
    test_date: testStart.test_date,
    models: 'GPT 5.2 Neuro/Polza + Claude 4.5 fallback',
    input_chunk_id: dbResult.id_chunk,
    total_duration_ms: totalDuration,
    total_duration_sec: round(totalDuration / 1000, 1),
    translate_result: translateResult,
    report: report,
    success: translateResult && !translateResult.error
  }
}];

function round(n, d) { return Math.round(n * Math.pow(10, d)) / Math.pow(10, d); }

const result = $input.first().json;
console.log('✅ BASELINE TEST COMPLETED');
console.log('📊 Duration: ' + result.total_duration_sec + 's');
console.log('✅ Success: ' + result.success);
return [{ json: result }];
